const data = $input.first().json;

if (!data.ok || !data.leads || data.leads.length === 0) {
  return [{ json: { hasReady: false, readyCount: 0, leads: [], html: '' } }];
}

const readyLeads = data.leads
  .filter(l => l.readiness === 'READY')
  .sort((a, b) => (b.score || 0) - (a.score || 0));

if (readyLeads.length === 0) {
  return [{ json: { hasReady: false, readyCount: 0, leads: [], html: '' } }];
}

const renderSignal = (l) => `
<div style="border:2px solid #16a34a;border-radius:8px;padding:12px;margin:8px 0;background:#f0fdf4">
  <strong style="font-size:16px">${l.title || 'Signal'}</strong>
  <p style="margin:4px 0;color:#374151">${l.whyNow || ''}</p>
  <p style="margin:4px 0">
    <span style="background:#16a34a;color:white;padding:2px 8px;border-radius:4px;font-size:12px">READY</span>
    Score: <strong>${l.score}</strong> &nbsp; Trade: ${l.trade} &nbsp; Location: ${l.location || l.postcodeOutward || ''}
  </p>
  <p style="margin:4px 0;font-size:13px;color:#6b7280">Evidence: ${(l.evidenceBadges || []).join(' · ')}</p>
  <p style="margin:4px 0;font-size:13px"><strong>Action:</strong> ${l.recommendedAction || ''}</p>
  ${l.url ? `<p style="margin:4px 0"><a href="${l.url}">View source</a></p>` : ''}
</div>`;

const html = `
<h2 style="color:#16a34a">${readyLeads.length} READY Signal${readyLeads.length > 1 ? 's' : ''} — Act now</h2>
<p style="color:#6b7280">${new Date().toLocaleString('en-GB')}</p>
${readyLeads.map(renderSignal).join('')}
<p style="color:#6b7280;font-size:12px">Region: ${data.region} · Sources: ${(data.sources || []).join(', ')}</p>`;

return [{ json: { hasReady: true, readyCount: readyLeads.length, leads: readyLeads, html } }];
